import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"哨兵","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/哨兵.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/哨兵.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/哨兵.md"};function d(l,a,b,i,_,c){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"哨兵",tabindex:"-1"},[n("哨兵 "),e("a",{class:"header-anchor",href:"#哨兵","aria-label":'Permalink to "哨兵"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序006")])])],-1),s('<h1 id="哨兵-1" tabindex="-1">哨兵 <a class="header-anchor" href="#哨兵-1" aria-label="Permalink to &quot;哨兵&quot;">​</a></h1><p>哨兵 狙击步枪<br> C+1500<br> 科技本质</p><p>由拉斯提莫沙军械库为apex竞赛提供的特殊型号栓动式狙击步枪，射程和伤害都在时间的考验下得到了验证。</p><p>武器伤害：18L  射程200   穿甲3 高速5  装弹数6+1</p><p>这是一把拥有着哑光黑色的枪身的狙击枪，为了保证精良的射程与杀伤力，采用了独特的枪身设计，枪栓可转动能<br> 量附属装置，起到充能和换弹的效果，但设计者出于其对老式栓动单发步枪的情怀，加入了传统步枪的射击模式，使用<br> 该步枪击发前需要一个移动动作进行手动上膛、攻击后需要一个迅捷动作进行退弹。这把狙击步枪具有【猎头者】 和【重创】和【充能】的特性。</p><p>【猎头者】<br> 以一个标准动作，对敌对目标的头部进行一次射击，这次射击不计算任何能力提升，且出数大于总数的一半（不包<br> 含附加成功带来的数值），则此次攻击中每有1点附加，就提升1点（这个效果不会和毁灭、湮灭共同生效）。与此同时，目标的头上会亮起一个字体加重加<br> 粗的140（充能后将变为176）的数字，这视为一个攻击技。</p><p>【重创】<br> 被这把枪射中头部者，将受到等同于伤害出目肢体妨碍点数，这不是一个部位攻击。使用标准强韧豁免进行对抗。<br> 若攻击时，被攻击者已陷入严重状态时，则此次攻击视为进入了毁灭状态，可以以恢复严重状态般恢复，但如果<br> 造成的异常点数累计达到毁灭状态，则视为进入真正的毁灭状态。</p><p>【充能】<br> 你可以使用一个移动动作拉动枪栓，并连接一枚小型护盾电池为枪械充能。<br> 此时枪械可以获得6L的伤害提升，同时获得5威猛，持续一场景</p><p>小型护盾电池：750分一枚<br> 用于补充护盾能量的能量电池，也可以用于武器的充能</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
